def create_nncf_model_and_single_algo_builder(model: Module, config: NNCFConfig, dummy_forward_fn: Callable[[Module], Any]=None, wrap_inputs_fn: Callable[[Tuple, Dict], Tuple[Tuple, Dict]]=None) -> Tuple[NNCFNetwork, PTCompressionAlgorithmController]:
    assert isinstance(config, NNCFConfig)
    NNCFConfig.validate(config)
    input_info = FillerInputInfo.from_nncf_config(config)
    scopes_without_shape_matching = config.get('scopes_without_shape_matching', [])
    ignored_scopes = config.get('ignored_scopes')
    target_scopes = config.get('target_scopes')
    compressed_model = NNCFNetwork(model, input_info=input_info, dummy_forward_fn=dummy_forward_fn, wrap_inputs_fn=wrap_inputs_fn, ignored_scopes=ignored_scopes, target_scopes=target_scopes, scopes_without_shape_matching=scopes_without_shape_matching)
    algo_names = extract_algorithm_names(config)
    assert len(algo_names) == 1
    algo_name = next(iter(algo_names))
    builder_cls = PT_COMPRESSION_ALGORITHMS.get(algo_name)
    builder = builder_cls(config, should_init=True)
    return (compressed_model, builder)

